# ── Keyring helper (optional dependency) ──────────────────
# Provides secure OS-level credential storage for the GitHub
# token.  If the keyring package is not installed the app
# continues to work; the token is simply not persisted across
# sessions via the keyring.
_KEYRING_SERVICE  = "film_forge"
_KEYRING_USERNAME = "github_token"
try:
    import keyring as _keyring_mod
    _KEYRING_AVAILABLE = True
except ImportError:
    _keyring_mod = None          # type: ignore
    _KEYRING_AVAILABLE = False

def keyring_get_gh_token() -> str:
    """Return the stored GitHub token, or '' if unavailable."""
    if not _KEYRING_AVAILABLE:
        return ""
    try:
        value = _keyring_mod.get_password(_KEYRING_SERVICE, _KEYRING_USERNAME)
        return value or ""
    except Exception:
        return ""

def keyring_set_gh_token(token: str) -> bool:
    """Store *token* in the system keyring. Returns True on success."""
    if not _KEYRING_AVAILABLE:
        return False
    try:
        if token:
            _keyring_mod.set_password(_KEYRING_SERVICE, _KEYRING_USERNAME, token)
        else:
            try:
                _keyring_mod.delete_password(_KEYRING_SERVICE, _KEYRING_USERNAME)
            except Exception:
                pass
        return True
    except Exception:
        return False

