# ── OMDb API ──────────────────────────────────────────────
# Resolution order:
#   1. OMDB_API_KEY environment variable
#   2. "omdb_api_key" in film_forge_config.json (same directory as this file)
#   3. Empty string — user must enter key in Settings on first run
def _resolve_omdb_api_key() -> str:
    # 1. Environment variable
    env_key = os.environ.get("OMDB_API_KEY", "").strip()
    if env_key:
        return env_key
    # 2. Local config file (written by Settings → Apply)
    try:
        _cfg_path = Path(SCRIPT_DIR) / "film_forge_config.json"
        if _cfg_path.exists():
            _cfg = json.loads(_cfg_path.read_text())
            cfg_key = _cfg.get("omdb_api_key", "").strip()
            if cfg_key:
                return cfg_key
    except Exception:
        pass
    # No key found — return empty; app will skip OMDb lookups until user enters one
    return ""

OMDB_API_KEY  = _resolve_omdb_api_key()
OMDB_SESSION  = requests.Session()

