def show_message_box(title, message, type="info"):
    if type == "error":
        messagebox.showerror(title, message)
    else:
        messagebox.showinfo(title, message)


def find_excel_path():
    possible_paths = [
        r"C:\Program Files\Microsoft Office\root\Office16\EXCEL.EXE",
        r"C:\Program Files (x86)\Microsoft Office\root\Office16\EXCEL.EXE",
        r"C:\Program Files\Microsoft Office\Office15\EXCEL.EXE",
        r"C:\Program Files (x86)\Microsoft Office\Office15\EXCEL.EXE",
    ]
    for path in possible_paths:
        if os.path.exists(path):
            return path
    return None


def open_file(file_path):
    try:
        if platform.system() == "Windows":
            os.startfile(file_path)
            return
        elif platform.system() == "Darwin":
            subprocess.Popen(["open", file_path])
        else:
            subprocess.Popen(["xdg-open", file_path])
    except Exception as e:
        show_message_box(
            "Open Failed",
            f"Could not open the file automatically.\n\n{e}\n\n"
            "Tip: Make sure .xlsx files are associated with Excel (or another spreadsheet app).",
            type="error",
        )


def load_imdb_ids():
    try:
        if os.path.exists(IMDB_ID_FILE):
            with open(IMDB_ID_FILE, 'r') as f:
                return json.load(f)
        return {}
    except Exception as e:
        print(f"Error loading IMDb IDs: {str(e)}")
        return {}


def save_imdb_ids(imdb_id_store):
    try:
        directory = os.path.dirname(IMDB_ID_FILE)
        if not os.path.exists(directory):
            os.makedirs(directory)
        with open(IMDB_ID_FILE, 'w') as f:
            json.dump(imdb_id_store, f, indent=4)
        print("IMDb IDs saved successfully.")
    except FileNotFoundError:
        print(f"Error: Directory '{os.path.dirname(IMDB_ID_FILE)}' does not exist.")
    except PermissionError:
        print(f"Error: Permission denied while saving IMDb IDs to '{IMDB_ID_FILE}'.")
    except Exception as e:
        print(f"Error saving IMDb IDs: {e}")


