def fetch_data_by_imdb_id(imdb_id, retries=3, session=None):
    url = f"http://www.omdbapi.com/?i={imdb_id}&apikey={OMDB_API_KEY}"
    while retries > 0:
        try:
            s = session or OMDB_SESSION
            response = s.get(url, timeout=10)
            if response.status_code == 200:
                data = response.json()
                if data['Response'] == 'True':
                    poster = data.get('Poster', '')
                    if poster and poster.lower() == 'n/a':
                        poster = ''
                    return (
                        data.get('imdbID', ''), data.get('Title', ''),
                        data.get('Runtime', ''), data.get('Genre', ''),
                        data.get('Rated', ''), data.get('Actors', ''),
                        data.get('Plot', ''), poster,
                    )
                else:
                    print(f"OMDb API Error: {data.get('Error', 'Unknown error')} for IMDb ID {imdb_id}")
                    break
            else:
                print(f"Error fetching data for IMDb ID '{imdb_id}': HTTP {response.status_code}")
                break
        except (requests.ConnectionError, requests.Timeout) as e:
            retries -= 1
            if retries > 0:
                print(f"Network error: {e}. Retrying in 5 seconds… ({retries} retries left)")
                time.sleep(5)
            else:
                print(f"Failed to fetch data for IMDb ID '{imdb_id}' after multiple attempts. Error: {e}")
        except Exception as e:
            print(f"Unexpected error fetching data for IMDb ID '{imdb_id}': {e}")
            break
    return None, None, None, None, None, None, None, None


def fetch_data_by_title_year(title, year, retries=3, session=None):
    if title.lower() == "bill & teds bogus journey":
        title = "Bill and Ted's Bogus Journey"
    title_enc = quote(title)
    url = f"http://www.omdbapi.com/?t={title_enc}&y={year}&apikey={OMDB_API_KEY}"
    while retries > 0:
        try:
            s = session or OMDB_SESSION
            response = s.get(url, timeout=10)
            if response.status_code == 200:
                data = response.json()
                if data['Response'] == 'True':
                    poster = data.get('Poster', '')
                    if poster and poster.lower() == 'n/a':
                        poster = ''
                    return (
                        data.get('imdbID', ''), data.get('Title', ''),
                        data.get('Runtime', ''), data.get('Genre', ''),
                        data.get('Rated', ''), data.get('Actors', ''),
                        data.get('Plot', ''), poster,
                    )
                else:
                    print(f"OMDb API Error: {data.get('Error', 'Unknown error')} for '{title} ({year})'")
                    break
            else:
                print(f"Error fetching data for '{title} ({year})': HTTP {response.status_code}")
                break
        except (requests.ConnectionError, requests.Timeout) as e:
            retries -= 1
            if retries > 0:
                print(f"Network error: {e}. Retrying in 5 seconds… ({retries} retries left)")
                time.sleep(5)
            else:
                print(f"Failed to fetch data for '{title} ({year})' after multiple attempts. Error: {e}")
        except Exception as e:
            print(f"Unexpected error fetching data for '{title} ({year})': {e}")
            break
    return None, None, None, None, None, None, None, None


