POSTER_CACHE_DIR = Path(_USER_DIR) / "posters"

def download_poster(imdb_id: str, poster_url: str) -> str:
    """
    Download a poster image to the local posters folder for GUI display caching.
    Always returns the original remote URL — that is what gets stored in the DB
    so Railway and the web server can use it directly without needing local files.
    """
    if not poster_url or poster_url.lower() in ("", "n/a"):
        return ""
    if not imdb_id:
        return poster_url

    try:
        POSTER_CACHE_DIR.mkdir(parents=True, exist_ok=True)
        local_path = POSTER_CACHE_DIR / f"{imdb_id}.jpg"

        if not local_path.exists():
            resp = requests.get(poster_url, timeout=15)
            resp.raise_for_status()
            img = Image.open(io.BytesIO(resp.content)).convert("RGB")
            img.save(local_path, "JPEG", quality=90)
            print(f"[poster] cached locally → {local_path}")

    except Exception as e:
        print(f"[poster] local cache failed for {imdb_id}: {e}")

    # Always return the remote URL for DB storage
    return poster_url


