def scan_for_video_files(directories, update_callback):
    video_files = []
    total_scanned = 0
    UI_UPDATE_EVERY = 100
    for directory in directories:
        for root, _, files in os.walk(directory):
            for file in files:
                if any(file.lower().endswith(ext) for ext in VIDEO_EXTENSIONS):
                    video_files.append(os.path.join(root, file))
                total_scanned += 1
                if total_scanned % UI_UPDATE_EVERY == 0:
                    update_callback(total_scanned, len(video_files))
    update_callback(total_scanned, len(video_files))
    return video_files


def extract_title_year_imdb(file_path):
    try:
        file_name = os.path.basename(file_path)
        match = re.match(r"(.+?)\s+\((\d{4})\)\s*(?:'([^']*)')?\s*\(?(tt\d+)?\)?", file_name)
        if match:
            title   = match.group(1).strip()
            year    = match.group(2).strip()
            edition = match.group(3).strip() if match.group(3) else None
            imdb_id = match.group(4).strip() if match.group(4) else None
            return title, year, edition, imdb_id
        else:
            title, _ = os.path.splitext(file_name)
            return title.strip(), None, None, None
    except Exception as e:
        print(f"Error parsing filename: {file_path} - {str(e)}")
        return "", None, None, None


