def save_to_excel(movie_data_list, file_path):
    try:
        df = pd.DataFrame(movie_data_list, columns=[
            'Film Title', 'Date', 'Runtime', 'Genre', 'MPAA Rating',
            'Edition', 'Starring', 'Plot Summary',
            'Date Added', 'File Extension',
        ])
        if 'Film Title' in df.columns:
            df.sort_values(by='Film Title', inplace=True, na_position='last')

        with pd.ExcelWriter(file_path, engine='openpyxl') as writer:
            df.to_excel(writer, index=False, sheet_name='Files', startrow=4)
            wb = writer.book
            ws = wb['Files']

            ws.merge_cells('A1:K1')
            ws['A1'] = f"Film Forge - Version {__version__}"
            ws['A1'].font = Font(bold=True, size=14)
            ws['A1'].alignment = Alignment(horizontal="center")

            current_datetime = datetime.now().strftime("%m/%d/%Y %I:%M %p")
            ws.merge_cells('A2:K2')
            ws['A2'] = f"File created on: {current_datetime}"
            ws['A2'].font = Font(bold=True)
            ws['A2'].alignment = Alignment(horizontal="left")

            ws.merge_cells('A3:K3')
            ws['A3'] = f"Total Films in Database: {len(df)}"
            ws['A3'].font = Font(bold=True)
            ws['A3'].alignment = Alignment(horizontal="left")

            column_settings = {
                'A': (23, True), 'B': (10, True), 'C': (12, True),
                'D': (20, True), 'E': (14, True), 'F': (11, True),
                'G': (40, True), 'H': (72, True), 'I': (15, True),
                'J': (18, True), 'K': (12, True),
            }
            for col_letter, (col_width, wrap_text) in column_settings.items():
                ws.column_dimensions[col_letter].width = col_width
                for cell in ws[col_letter]:
                    cell.alignment = Alignment(
                        wrap_text=wrap_text, vertical='top',
                        horizontal='center' if col_letter in ['B', 'C', 'E', 'F', 'I', 'J', 'K'] else 'left',
                    )

            ws.auto_filter.ref = f"A5:K{ws.max_row}"

            light_blue_fill = PatternFill(start_color="DDEBF7", end_color="DDEBF7", fill_type="solid")
            dark_blue_fill  = PatternFill(start_color="BDD7EE", end_color="BDD7EE", fill_type="solid")
            ws.conditional_formatting.add(
                f"A5:K{ws.max_row}",
                FormulaRule(formula=["=MOD(ROW(),2)=0"], stopIfTrue=True, fill=light_blue_fill))
            ws.conditional_formatting.add(
                f"A5:K{ws.max_row}",
                FormulaRule(formula=["=MOD(ROW(),2)=1"], stopIfTrue=True, fill=dark_blue_fill))
        return True
    except Exception as e:
        show_message_box("Error", f"Failed to save to Excel: {str(e)}", type="error")
        return False


def export_movies_ndjson(movie_data_list, out_path):
    try:
        os.makedirs(os.path.dirname(out_path), exist_ok=True)
        with open(out_path, "w", encoding="utf-8") as f:
            for doc in movie_data_list:
                f.write(json.dumps(doc, ensure_ascii=False) + "\n")
        print("NDJSON export complete.")
    except Exception as e:
        print(f"Error exporting NDJSON: {e}")


