def safe_ui_update(root, func, *args):
    root.after(0, func, *args)


def process_files_and_fetch_data(movie_titles, update_callback, update_missing_count,
                                  eta_callback, on_complete, root):
    global movie_data
    movie_data = []
    imdb_id_store = load_imdb_ids()
    skipped_movies = []
    safe_ui_update(root, update_missing_count, 0)

    total_titles = len(movie_titles)
    start_time   = time.time()

    db = MovieDB(DB_PATH, SCHEMA_PATH)

    for index, (title, year, edition, imdb_id, file_path) in enumerate(movie_titles, start=1):
        try:
            cached = None
            if OMDB_USE_CACHE and (not OMDB_REFRESH):
                try:
                    if imdb_id:
                        cached = db.get_cached_omdb_by_imdb(imdb_id)
                    if not cached:
                        cached = db.get_cached_omdb_by_title_year(title, year)
                except Exception:
                    cached = None

            if cached:
                fetched_imdb_id = (cached.get('imdbID') or '').strip()
                official_title  = (cached.get('Title')  or '').strip()
                runtime = cached.get('Runtime', '')
                genre   = cached.get('Genre',   '')
                rating  = cached.get('Rated',   '')
                actors  = cached.get('Actors',  '')
                plot    = cached.get('Plot',    '')
            else:
                fetched_imdb_id, official_title, runtime, genre, rating, actors, plot, _poster = (
                    fetch_data_by_imdb_id(imdb_id, session=OMDB_SESSION)
                    if imdb_id else
                    fetch_data_by_title_year(title, year, session=OMDB_SESSION)
                )

            if not official_title:
                skipped_movies.append(f"{title} ({year})")
                safe_ui_update(root, update_missing_count, len(skipped_movies))
                continue

            movie_data.append({
                'Film Title':  official_title or title,
                'Date':         year    or '',
                'Runtime':      runtime or '',
                'Genre':        genre   or '',
                'MPAA Rating':  rating  or '',
                'Edition':      edition or '',
                'Starring':     actors  or '',
                'Plot Summary': plot    or '',
                'IMDb ID':      fetched_imdb_id or '',
                'File Path':    file_path,
                'File Extension': os.path.splitext(file_path)[1],
                'Date Added':   datetime.now().strftime("%m/%d/%y"),
                'imdb_key':     fetched_imdb_id or '',
                'title_year_key': f"{(official_title or title).strip().upper()}|{(year or '').strip()}",
            })

            omdb_json = {
                "imdbID":  fetched_imdb_id or "",
                "Title":   official_title or title or "",
                "Year":    year    or "",
                "Runtime": runtime or "",
                "Genre":   genre   or "",
                "Rated":   rating  or "",
                "Actors":  actors  or "",
                "Plot":    plot    or "",
            }
            try:
                movie_id_db = db.upsert_movie(omdb_json)
                db.upsert_file(movie_id_db, file_path, do_hash=HASH_DURING_PROCESS)
            except Exception as _db_err:
                logging.exception(f"DB write failed for {file_path}: {_db_err}")

            if fetched_imdb_id:
                imdb_id_store[official_title] = fetched_imdb_id

        except Exception as e:
            print(f"Error processing movie: {title} - {str(e)}")

        update_callback(index, total_titles)
        elapsed          = time.time() - start_time
        remaining_time   = (elapsed / index) * (total_titles - index)
        safe_ui_update(root, eta_callback, int(remaining_time))

    save_imdb_ids(imdb_id_store)

    if skipped_movies:
        safe_ui_update(root, messagebox.showinfo, "Skipped Movies",
               "The following movies were skipped due to missing data:\n\n" + "\n".join(skipped_movies))

    safe_ui_update(root, on_complete)


