def create_export_window(movie_data_list, root, total_files_scanned):
    export_window = tk.Toplevel(root)
    export_window.title("Export File Data to Excel")
    export_window.geometry("300x150")
    export_window.attributes('-topmost', True)
    center_window(export_window, root)

    def export_to_excel():
        file_path = ""
        try:
            export_window.attributes('-topmost', False)
            current_date    = datetime.now().strftime("%Y-%m-%d")
            default_filename = f"File_Forge_{current_date}.xlsx"
            file_path = filedialog.asksaveasfilename(
                parent=export_window,
                defaultextension=".xlsx",
                initialfile=default_filename,
                filetypes=[("Excel files", "*.xlsx"), ("All files", "*.*")],
            )
            if not file_path:
                return
            success = save_to_excel(movie_data_list, file_path)
            if not success:
                show_message_box("Error", "Failed to export movie data.", type="error")
                return
            if messagebox.askyesno("Export Complete",
                                   "Excel file created successfully.\n\nOpen the file now?",
                                   parent=root):
                open_file(file_path)
            if export_window.winfo_exists():
                export_window.destroy()
            messagebox.showinfo("Export Complete", "Excel file created successfully.", parent=root)
        except Exception as e:
            show_message_box("Error", f"Export failed:\n{e}", type="error")
        finally:
            if file_path and export_window.winfo_exists():
                export_window.destroy()

    tk.Button(export_window, text="Export to Excel", command=export_to_excel).pack(pady=30)

    if len(movie_data_list) < total_files_scanned:
        show_message_box(
            "Warning",
            f"Only {len(movie_data_list)} out of {total_files_scanned} files were added. "
            "Please check for skipped files.",
            type="info",
        )


