def _load_embedded_icon(root):
    """Decode the embedded ICO and set it as the window icon."""
    try:
        ico_data = base64.b64decode(_ICON_B64)
        ico_img  = Image.open(io.BytesIO(ico_data))
        photo    = ImageTk.PhotoImage(ico_img.resize((32, 32), Image.LANCZOS))
        root.iconphoto(True, photo)
        root._icon_photo = photo          # keep reference
    except Exception as e:
        print(f"[icon] failed: {e}")


class SplashScreen(tk.Toplevel):
    """Borderless splash shown while the main window initialises."""

    DURATION_MS = 2800   # total display time

    def __init__(self, parent):
        super().__init__(parent)
        self.overrideredirect(True)   # no title bar / border

        # Decode splash image
        try:
            data   = base64.b64decode(_SPLASH_B64)
            pil    = Image.open(io.BytesIO(data))
            self._photo = ImageTk.PhotoImage(pil)
            W, H   = pil.width, pil.height
        except Exception:
            self._photo = None
            W, H = 500, 300

        # Position off-screen first, then centre after window is realized
        self.geometry(f"{W}x{H}+-9999+-9999")
        self.update_idletasks()
        sw = self.winfo_screenwidth()
        sh = self.winfo_screenheight()
        x  = (sw - W) // 2
        y  = (sh - H) // 2
        self.geometry(f"{W}x{H}+{x}+{y}")
        self.update()
        self.lift()
        self.attributes("-topmost", True)

        # Canvas
        canvas = tk.Canvas(self, width=W, height=H, highlightthickness=0, bg="#12161e")
        canvas.pack()

        if self._photo:
            canvas.create_image(0, 0, anchor="nw", image=self._photo)

        # Animated loading bar — positioned near bottom of splash (1200x320)
        bar_x1, bar_y1 = 100, 296
        bar_x2, bar_y2 = 100 + 1000, 296 + 8
        self._bar_bg = canvas.create_rectangle(
            bar_x1, bar_y1, bar_x2, bar_y2,
            fill="#12161e", outline="#ff8c00", width=1)
        self._bar = canvas.create_rectangle(
            bar_x1, bar_y1, bar_x1, bar_y2,
            fill="#ff8c00", outline="")
        self._canvas   = canvas
        self._bar_x1   = bar_x1
        self._bar_x2   = bar_x2
        self._bar_y1   = bar_y1
        self._bar_y2   = bar_y2
        self._start_ms = None
        self.after(30, self._animate)

    def _animate(self):
        if self._start_ms is None:
            self._start_ms = self.tk.call("clock", "milliseconds")
        now     = self.tk.call("clock", "milliseconds")
        elapsed = int(now) - int(self._start_ms)
        pct     = min(elapsed / self.DURATION_MS, 1.0)
        fill_x  = self._bar_x1 + int((self._bar_x2 - self._bar_x1) * pct)
        self._canvas.coords(self._bar,
                            self._bar_x1, self._bar_y1,
                            fill_x,       self._bar_y2)
        if pct < 1.0:
            self.after(30, self._animate)

    def close(self):
        self.destroy()

