    # ── Startup: restore previous scan from SQLite ──────────────
    
    def _startup_load_from_db(self):
        def worker():
            rows = []
            err  = ""
            try:
                db = MovieDB(DB_PATH, None)
                rows = db.conn.execute("""
                    SELECT m.title, m.year, m.runtime, m.mpaa_rating,
                           m.imdb_id, m.genre, m.actors, m.plot, m.poster,
                           m.omdb_json,
                           MIN(f.path)                  AS path,
                           COALESCE(um.watched, 0)      AS watched,
                           um.personal_rating           AS personal_rating
                    FROM   movies m
                    LEFT JOIN files      f  ON f.movie_id  = m.movie_id
                    LEFT JOIN user_movie um ON um.movie_id = m.movie_id
                    GROUP BY m.movie_id
                    ORDER BY m.title ASC
                """).fetchall()
                db.close()
            except Exception as e:
                err = str(e)

            def apply():
                if err:
                    self.status_var.set(f"DB load error: {err}")
                    return
                if not rows:
                    self.status_var.set("Ready — no previous scan found. Add folders and scan.")
                    return
                self._clear_movies()
                self.movie_titles = []
                for r in rows:
                    title   = r["title"]       or ""
                    year    = str(r["year"]    or "")
                    runtime = r["runtime"]     or ""
                    mpaa    = r["mpaa_rating"] or ""
                    imdb_id = r["imdb_id"]     or ""
                    genre   = r["genre"]       or ""
                    actors  = r["actors"]      or ""
                    plot    = r["plot"]        or ""
                    fp      = r["path"]        or ""
                    watched = "Yes" if int(r["watched"] or 0) == 1 else ""
                    _pr = r["personal_rating"]
                    rating  = "" if _pr is None else ("★" * int(round(_pr))) + ("☆" * (5 - int(round(_pr))))

                    poster_url = r["poster"] or ""
                    if not poster_url or poster_url.lower() == "n/a":
                        try:
                            blob = r["omdb_json"]
                            if blob:
                                poster_url = json.loads(blob).get("Poster", "") or ""
                        except Exception:
                            poster_url = ""
                    if poster_url.lower() == "n/a":
                        poster_url = ""

                    iid = self.movies_tree.insert("", "end",
                        values=(title, year, runtime, mpaa, watched, rating))
                    self.details_by_item[iid] = {
                        "genre": genre, "actors": actors,
                        "plot": plot, "poster_url": poster_url,
                    }
                    self.movie_titles.append((title, year, None, imdb_id, fp))

                self.movies_var.set(len(rows))
                self.processed_var.set(f"{len(rows)}/{len(rows)}")
                self.status_var.set(f"Loaded {len(rows):,} movies from database. Scan again to pick up new files.")
                self._set_idle_state()

            self.after(0, apply)

        threading.Thread(target=worker, daemon=True).start()

