    # ── Poster helpers ───────────────────────────────────────────
    def _poster_draw_placeholder(self):
        c = self._poster_canvas
        c.delete("all")
        cw, ch = int(c["width"]), int(c["height"])
        c.create_rectangle(0, 0, cw, ch, fill="#1e1e1e", outline="")
        cx, cy = cw // 2, ch // 2 - 14
        R = min(cw, ch) // 2 - 14
        c.create_oval(cx-R, cy-R, cx+R, cy+R, outline="#606060", fill="#2e2e2e", width=3)
        hub = R // 3
        c.create_oval(cx-hub, cy-hub, cx+hub, cy+hub, outline="#606060", fill="#1e1e1e", width=2)
        hole_r, hole_orb = R // 5, int(R * 0.62)
        for k in range(6):
            import math as _m
            angle = _m.radians(k * 60)
            hx = cx + int(hole_orb * _m.cos(angle))
            hy = cy + int(hole_orb * _m.sin(angle))
            c.create_oval(hx-hole_r, hy-hole_r, hx+hole_r, hy+hole_r,
                          outline="#606060", fill="#1e1e1e", width=1)
        sy = cy + R + 8
        c.create_rectangle(8, sy, cw-8, sy+14, fill="#3a3a3a", outline="#606060", width=1)
        x = 14
        while x + 6 <= cw - 14:
            c.create_rectangle(x, sy+3, x+6, sy+11, fill="#1e1e1e", outline="#606060", width=1)
            x += 20

    def _poster_show_image(self, img: Image.Image):
        c = self._poster_canvas
        img.thumbnail((POSTER_MAX_W, POSTER_MAX_H), Image.LANCZOS)
        iw, ih = img.size
        c.config(width=iw, height=ih)
        photo = ImageTk.PhotoImage(img)
        self._poster_photo = photo
        c.delete("all")
        c.create_image(0, 0, anchor="nw", image=photo)

    def _poster_load(self, imdb_id: str, poster_url: str):
        self._poster_load_token += 1
        token = self._poster_load_token
        self._poster_photo = None
        self._poster_draw_placeholder()

        def worker():
            img = None
            if imdb_id:
                cache_path = self._poster_cache_dir / f"{imdb_id}.jpg"
                if cache_path.exists():
                    try:
                        img = Image.open(cache_path).convert("RGB")
                    except Exception:
                        cache_path.unlink(missing_ok=True)
            if img is None and poster_url and poster_url.lower() not in ("", "n/a"):
                try:
                    resp = requests.get(poster_url, timeout=10)
                    resp.raise_for_status()
                    img = Image.open(io.BytesIO(resp.content)).convert("RGB")
                    if imdb_id:
                        try:
                            img.save(self._poster_cache_dir / f"{imdb_id}.jpg", "JPEG", quality=90)
                        except Exception:
                            pass
                except Exception:
                    img = None

            def apply():
                if self._poster_load_token != token:
                    return
                if img:
                    self._poster_show_image(img)
                else:
                    self._poster_draw_placeholder()
            self.after(0, apply)

        threading.Thread(target=worker, daemon=True).start()

    def _poster_load_for_imdb(self, imdb_id: str, title: str = "", year: str = ""):
        def worker():
            poster_url  = ""
            resolved_id = imdb_id
            if resolved_id:
                cache_path = self._poster_cache_dir / f"{resolved_id}.jpg"
                if cache_path.exists():
                    self.after(0, lambda: self._poster_load(resolved_id, ""))
                    return
            if resolved_id:
                try:
                    db  = MovieDB(DB_PATH, None)
                    row = db.conn.execute(
                        "SELECT poster, omdb_json FROM movies WHERE imdb_id=? LIMIT 1",
                        (resolved_id,)).fetchone()
                    db.close()
                    if row:
                        poster_url = row["poster"] or ""
                        if not poster_url or poster_url.lower() == "n/a":
                            try:
                                blob = row["omdb_json"]
                                if blob:
                                    poster_url = json.loads(blob).get("Poster", "") or ""
                            except Exception:
                                pass
                        if poster_url.lower() == "n/a":
                            poster_url = ""
                except Exception:
                    pass
            if not poster_url and resolved_id:
                try:
                    resp = requests.get(
                        f"http://www.omdbapi.com/?i={resolved_id}&apikey={OMDB_API_KEY}",
                        timeout=10)
                    resp.raise_for_status()
                    data = resp.json()
                    if data.get("Response") == "True":
                        poster_url = data.get("Poster", "") or ""
                        if poster_url.lower() == "n/a":
                            poster_url = ""
                except Exception:
                    pass
            if not poster_url and not resolved_id and title:
                try:
                    yr = str(year).strip() if year else ""
                    q  = f"http://www.omdbapi.com/?t={quote(title)}"
                    if yr: q += f"&y={yr}"
                    q += f"&apikey={OMDB_API_KEY}"
                    resp = requests.get(q, timeout=10)
                    resp.raise_for_status()
                    data = resp.json()
                    if data.get("Response") == "True":
                        poster_url  = data.get("Poster", "") or ""
                        resolved_id = data.get("imdbID",  "") or ""
                        if poster_url.lower() == "n/a":
                            poster_url = ""
                except Exception:
                    pass
            self.after(0, lambda: self._poster_load(resolved_id, poster_url))

        threading.Thread(target=worker, daemon=True).start()

