    def _db_clear(self):
        for iid in self.db_tree.get_children():
            self.db_tree.delete(iid)

    def _db_insert_sqlite_row(self, r):
        watched   = "Yes" if int(r["watched"] or 0) == 1 else "No"
        _pr = r["personal_rating"]
        my_rating = "" if _pr is None else ("★" * int(round(_pr))) + ("☆" * (5 - int(round(_pr))))
        self.db_tree.insert("", "end", values=(
            r["title"] or "", r["year"] or "", "",
            r["imdb_id"] or "", r["mpaa_rating"] or "",
            r["genre"] or "", r["actors"] or "", watched, my_rating))

    def _db_load_all(self):
        self._db_clear()
        self._db_loaded_once = True
        try:
            db = MovieDB(DB_PATH, None)
            rows  = db.search_page("", 0, 500)
            total = db.count_filtered("")
            db.close()
        except Exception as e:
            messagebox.showerror("SQLite", f"Failed to load records.\n\n{e}")
            return
        for r in rows:
            self._db_insert_sqlite_row(r)
        self._db_source_var.set(f"SQLite  ({total} movies)")
        self._db_count_var.set(f"{len(rows)} rows shown")

    def _db_search(self):
        self._db_clear()
        q = (self.db_search_var.get() or "").strip()
        try:
            db    = MovieDB(DB_PATH, None)
            rows  = db.search_page(q, 0, 500)
            total = db.count_filtered(q)
            db.close()
        except Exception as e:
            messagebox.showerror("SQLite", f"Search failed.\n\n{e}")
            return
        for r in rows:
            self._db_insert_sqlite_row(r)
        self._db_source_var.set(f"SQLite  ({total} matches)")
        self._db_count_var.set(f"{len(rows)} rows shown")

    def _db_open_selected(self, _evt=None):
        sel = self.db_tree.selection()
        if not sel:
            return
        values  = self.db_tree.item(sel[0], "values")
        title   = values[0] if len(values) > 0 else ""
        year    = values[1] if len(values) > 1 else ""
        runtime = values[2] if len(values) > 2 else ""
        mpaa    = values[4] if len(values) > 4 else ""
        genre   = values[5] if len(values) > 5 else ""
        actors  = values[6] if len(values) > 6 else ""
        imdb_id = values[3] if len(values) > 3 else ""
        plot = ""
        try:
            db  = MovieDB(DB_PATH, None)
            row = db.conn.execute("SELECT plot FROM movies WHERE imdb_id=? LIMIT 1", (imdb_id,)).fetchone()
            db.close()
            if row:
                plot = row["plot"] or ""
        except Exception:
            pass
        self.details_title_var.set(title)
        self.details_meta_var.set(f"{year} | {runtime} | {mpaa}")
        self.details_genre_var.set(genre)
        self.details_actors_var.set(actors)
        self.details_plot_text.delete("1.0", "end")
        self.details_plot_text.insert("1.0", plot)
        if imdb_id:
            self._poster_load_for_imdb(imdb_id)
        else:
            self._poster_load_token += 1
            self._poster_draw_placeholder()
        self.tabs.select(self.scan_tab)

    def _db_set_watched(self, val: int):
        sel = self.db_tree.selection()
        if not sel:
            return
        imdb_id = self.db_tree.item(sel[0], "values")[3]
        if not imdb_id:
            return
        try:
            db = MovieDB(DB_PATH, None)
            db.set_watched(imdb_id, val)
            db.close()
        except Exception as e:
            messagebox.showerror("SQLite", str(e))
            return
        vals = list(self.db_tree.item(sel[0], "values"))
        vals[7] = "Yes" if val else "No"
        self.db_tree.item(sel[0], values=vals)

    def _db_set_rating(self, stars=None):
        """Set rating to 1-5 stars, or clear with stars=None."""
        sel = self.db_tree.selection()
        if not sel:
            return
        imdb_id = self.db_tree.item(sel[0], "values")[3]
        if not imdb_id:
            return
        rating = float(stars) if stars is not None else None
        try:
            db = MovieDB(DB_PATH, None)
            db.set_rating(imdb_id, rating)
            db.close()
        except Exception as e:
            messagebox.showerror("SQLite", str(e))
            return
        vals = list(self.db_tree.item(sel[0], "values"))
        if rating is None:
            vals[8] = ""
        else:
            r_int = int(rating)
            vals[8] = ("★" * r_int) + ("☆" * (5 - r_int))
        self.db_tree.item(sel[0], values=vals)

    def _db_play_selected(self):
        """Launch the video file for the selected movie with the OS default player."""
        sel = self.db_tree.selection()
        if not sel:
            messagebox.showinfo("Play", "Select a movie first.")
            return

        imdb_id = self.db_tree.item(sel[0], "values")[3]
        if not imdb_id:
            messagebox.showwarning("Play", "No IMDb ID for this entry — can't look up the file.")
            return

        try:
            db = MovieDB(DB_PATH, None)
            rows = db.conn.execute(
                "SELECT f.path FROM files f "
                "JOIN movies m ON f.movie_id = m.movie_id "
                "WHERE m.imdb_id = ? ORDER BY f.path",
                (imdb_id,)
            ).fetchall()
            db.close()
        except Exception as e:
            messagebox.showerror("Play", f"Database error:\n{e}")
            return

        paths = [r["path"] for r in rows if r["path"]]

        if not paths:
            messagebox.showwarning("Play", "No file path found for this movie.\n"
                                   "Re-scan the folder to link the file.")
            return

        if len(paths) == 1:
            open_file(paths[0])
            return

        # Multiple files — let the user pick
        pick_win = tk.Toplevel(self)
        pick_win.title("Choose file to play")
        pick_win.resizable(True, False)
        center_window(pick_win, self)

        ttk.Label(pick_win, text="Multiple files found. Choose one to play:").pack(
            padx=12, pady=(10, 4), anchor="w")

        lb = tk.Listbox(pick_win, selectmode="single", width=80, height=min(len(paths), 8))
        for p in paths:
            lb.insert(tk.END, p)
        lb.pack(padx=12, pady=4, fill="x")
        lb.selection_set(0)

        def _play_picked():
            idx = lb.curselection()
            if idx:
                open_file(paths[idx[0]])
            pick_win.destroy()

        btn_row = ttk.Frame(pick_win)
        btn_row.pack(padx=12, pady=(4, 10), anchor="e")
        ttk.Button(btn_row, text="▶ Play", command=_play_picked).pack(side="left", padx=(0, 6))
        ttk.Button(btn_row, text="Cancel", command=pick_win.destroy).pack(side="left")

    def _db_save_backup(self):
        src = Path(DB_PATH)
        if not src.exists():
            messagebox.showerror("Backup", f"Database not found:\n{src}")
            return
        dest_dir = Path(r"D:\MDC\MDC V3_6")
        dest_dir.mkdir(parents=True, exist_ok=True)
        dest = dest_dir / "film_forge.db"
        try:
            shutil.copy2(src, dest)
            messagebox.showinfo("Backup", f"Saved to:\n{dest}")
        except Exception as e:
            messagebox.showerror("Backup", f"Save failed:\n{e}")

