    def _dup_refresh(self):
        for iid in self._dup_hash_tree.get_children(): self._dup_hash_tree.delete(iid)
        for iid in self._dup_imdb_tree.get_children(): self._dup_imdb_tree.delete(iid)
        for iid in self._dup_hash_file_tree.get_children(): self._dup_hash_file_tree.delete(iid)
        for iid in self._dup_imdb_file_tree.get_children(): self._dup_imdb_file_tree.delete(iid)
        self._dup_hash_files_map.clear()
        self._dup_imdb_files_map.clear()
        try:
            db = MovieDB(DB_PATH, None)
        except Exception as e:
            self._dup_status_var.set(f"Cannot open database: {e}")
            return

        # ── Hash duplicates ──────────────────────────────────────
        try:
            hash_rows = db.conn.execute("""
                SELECT sha256, COUNT(*) as c
                FROM files
                WHERE sha256 IS NOT NULL
                GROUP BY sha256
                HAVING c > 1
                ORDER BY c DESC
            """).fetchall()
        except Exception as e:
            hash_rows = []
        for r in hash_rows:
            iid = self._dup_hash_tree.insert("", "end", values=(r["sha256"], r["c"], ""))
            try:
                file_rows = db.conn.execute(
                    "SELECT path FROM files WHERE sha256=?", (r["sha256"],)
                ).fetchall()
                self._dup_hash_files_map[iid] = [(fr["path"], "") for fr in file_rows]
            except Exception as fe:
                self._dup_hash_files_map[iid] = []
        if not hash_rows:
            self._dup_hash_tree.insert("", "end", values=("No hash duplicates found.", "", ""))
        try:
            has_hashes = db.conn.execute("SELECT 1 FROM files WHERE sha256 IS NOT NULL LIMIT 1").fetchone()
            self._dup_hash_note.grid() if not has_hashes else self._dup_hash_note.grid_remove()
        except Exception:
            pass

        # ── IMDb duplicates ──────────────────────────────────────
        try:
            imdb_rows = db.conn.execute("""
                SELECT m.title, m.year, m.imdb_id, COUNT(f.file_id) as c
                FROM movies m
                JOIN files f ON f.movie_id = m.movie_id
                WHERE m.imdb_id IS NOT NULL AND m.imdb_id != ''
                GROUP BY m.imdb_id
                HAVING c > 1
                ORDER BY c DESC, m.title ASC
            """).fetchall()
        except Exception as e:
            imdb_rows = []
        for r in imdb_rows:
            iid = self._dup_imdb_tree.insert("", "end", values=(r["title"], r["year"] or "", r["imdb_id"], r["c"]))
            try:
                file_rows = db.conn.execute(
                    """SELECT f.path
                       FROM files f JOIN movies m ON f.movie_id = m.movie_id
                       WHERE m.imdb_id = ?""",
                    (r["imdb_id"],)
                ).fetchall()
                self._dup_imdb_files_map[iid] = [(fr["path"], "") for fr in file_rows]
            except Exception as fe:
                self._dup_imdb_files_map[iid] = []
        if not imdb_rows:
            self._dup_imdb_tree.insert("", "end", values=("No IMDb-ID duplicates found.", "", "", ""))
        db.close()
        self._dup_status_var.set(f"{len(hash_rows)} hash group(s), {len(imdb_rows)} IMDb duplicate(s) found.")

    def _on_hash_group_select(self, _evt=None):
        """Populate file-path detail panel when a hash group is selected."""
        for iid in self._dup_hash_file_tree.get_children():
            self._dup_hash_file_tree.delete(iid)
        self._dup_hash_path_var.set("")
        sel = self._dup_hash_tree.selection()
        if not sel:
            return
        files = self._dup_hash_files_map.get(sel[0], [])
        for fpath, fmb in files:
            fpath = os.path.normpath(fpath)
            exists = "✔ Yes" if os.path.isfile(fpath) else "✘ No"
            self._dup_hash_file_tree.insert("", "end", values=(fpath, exists))

    def _on_imdb_group_select(self, _evt=None):
        """Populate file-path detail panel when an IMDb duplicate group is selected."""
        for iid in self._dup_imdb_file_tree.get_children():
            self._dup_imdb_file_tree.delete(iid)
        self._dup_imdb_path_var.set("")
        sel = self._dup_imdb_tree.selection()
        if not sel:
            return
        files = self._dup_imdb_files_map.get(sel[0], [])
        for fpath, fmb in files:
            fpath = os.path.normpath(fpath)
            exists = "✔ Yes" if os.path.isfile(fpath) else "✘ No"
            self._dup_imdb_file_tree.insert("", "end", values=(fpath, exists))

    def _dup_open_folder(self, file_tree):
        """Open the folder containing the selected file in the OS file explorer."""
        sel = file_tree.selection()
        if not sel:
            messagebox.showinfo("Open Folder", "Select a file first.", parent=self)
            return
        fpath = os.path.normpath(file_tree.item(sel[0], "values")[0].strip())
        folder = os.path.dirname(fpath)
        if not os.path.isdir(folder):
            messagebox.showerror("Open Folder", f"Folder not found:\n{folder}", parent=self)
            return
        try:
            if platform.system() == "Windows":
                norm = os.path.normpath(fpath)
                if os.path.isfile(norm):
                    # /select, must be one argument with no space before the path
                    subprocess.Popen(f'explorer /select,"{norm}"', shell=True)
                else:
                    os.startfile(os.path.normpath(folder))
            elif platform.system() == "Darwin":
                if os.path.isfile(fpath):
                    subprocess.Popen(["open", "-R", fpath])   # -R reveals file in Finder
                else:
                    subprocess.Popen(["open", folder])
            else:
                subprocess.Popen(["xdg-open", folder])
        except Exception as e:
            messagebox.showerror("Open Folder", f"Could not open folder:\n{e}", parent=self)

    def _dup_delete_file(self, file_tree):
        """Delete the selected file from disk (with confirmation) and refresh."""
        sel = file_tree.selection()
        if not sel:
            messagebox.showinfo("Delete File", "Select a file first.", parent=self)
            return
        fpath = file_tree.item(sel[0], "values")[0].strip()
        # Normalise path — decode any escaped backslashes stored in the DB
        fpath = os.path.normpath(fpath)
        if not os.path.isfile(fpath):
            messagebox.showerror("Delete File",
                f"File not found on disk:\n\n{fpath}",
                parent=self)
            return
        fname = os.path.basename(fpath)
        confirmed = messagebox.askyesno(
            "Confirm Delete",
            f"Permanently delete this file?\n\n{fpath}\n\nThis cannot be undone.",
            icon="warning", parent=self,
        )
        if not confirmed:
            return
        try:
            os.remove(fpath)
            messagebox.showinfo("Deleted", f"Deleted:\n{fname}", parent=self)
            # Refresh the duplicates view so the removed file disappears
            self._dup_refresh()
        except Exception as e:
            messagebox.showerror("Delete Failed", f"Could not delete file:\n{e}", parent=self)

