    def _export_excel(self):
        if not self.movie_titles:
            messagebox.showinfo("Export", "No movies loaded. Run a scan first.", parent=self)
            return
        current_date  = datetime.now().strftime("%Y-%m-%d")
        file_path = filedialog.asksaveasfilename(
            parent=self, defaultextension=".xlsx",
            initialfile=f"File_Forge_{current_date}.xlsx",
            filetypes=[("Excel files", "*.xlsx"), ("All files", "*.*")])
        if not file_path:
            return
        movie_data_list = []
        items = self.movies_tree.get_children()
        for idx, (title, year, edition, imdb_id, file_path_movie) in enumerate(self.movie_titles):
            vals = self.movies_tree.item(items[idx], "values") if idx < len(items) else ()
            d    = self.details_by_item.get(items[idx] if idx < len(items) else "", {})
            movie_data_list.append({
                "Movie Title":    vals[0] if len(vals) > 0 else title or "",
                "Date":           vals[1] if len(vals) > 1 else year  or "",
                "Runtime":        vals[2] if len(vals) > 2 else "",
                "Genre":          d.get("genre",  ""),
                "MPAA Rating":    vals[3] if len(vals) > 3 else "",
                "Edition":        edition or "",
                "Starring":       d.get("actors", ""),
                "Plot Summary":   d.get("plot",   ""),
                "Date Added":     datetime.now().strftime("%m/%d/%y"),
                "File Extension": Path(file_path_movie).suffix if file_path_movie else "",
            })
        success = save_to_excel(movie_data_list, file_path)
        if success:
            self._export_excel_status.set(f"✔ Saved {len(movie_data_list)} rows → {Path(file_path).name}")
            if messagebox.askyesno("Export Complete",
                                   f"Exported {len(movie_data_list)} movies.\n\nOpen the file now?",
                                   parent=self):
                open_file(file_path)
        else:
            self._export_excel_status.set("✘ Export failed — check the log.")

    def _export_ndjson(self):
        if not self.movie_titles:
            messagebox.showinfo("Export", "No movies loaded. Run a scan first.", parent=self)
            return
        file_path = filedialog.asksaveasfilename(
            parent=self, defaultextension=".ndjson",
            initialfile=f"film_forge_{datetime.now().strftime('%Y-%m-%d')}.ndjson",
            filetypes=[("NDJSON files", "*.ndjson"), ("All files", "*.*")])
        if not file_path:
            return
        items = self.movies_tree.get_children()
        try:
            with open(file_path, "w", encoding="utf-8") as f:
                for idx, (title, year, edition, imdb_id, fp) in enumerate(self.movie_titles):
                    vals = self.movies_tree.item(items[idx], "values") if idx < len(items) else ()
                    d    = self.details_by_item.get(items[idx] if idx < len(items) else "", {})
                    f.write(json.dumps({
                        "title":       vals[0] if len(vals) > 0 else title or "",
                        "year":        vals[1] if len(vals) > 1 else year  or "",
                        "runtime":     vals[2] if len(vals) > 2 else "",
                        "mpaa_rating": vals[3] if len(vals) > 3 else "",
                        "genre":       d.get("genre",  ""),
                        "actors":      d.get("actors", ""),
                        "plot":        d.get("plot",   ""),
                        "imdb_id":     imdb_id or "",
                        "file_path":   fp or "",
                        "edition":     edition or "",
                    }, ensure_ascii=False) + "\n")
            self._export_ndjson_status.set(f"✔ Saved {len(self.movie_titles)} records → {Path(file_path).name}")
        except Exception as e:
            self._export_ndjson_status.set("✘ Export failed.")
            messagebox.showerror("NDJSON Export", str(e), parent=self)

