    # ── Config persistence ───────────────────────────────────────
    _CONFIG_PATH = Path(_USER_DIR) / "film_forge_config.json"

    def _config_load(self):
        try:
            cfg = json.loads(self._CONFIG_PATH.read_text())
            self.gh_repo_var.set(cfg.get("gh_repo",  "TMJ1972/my-movie-database"))
            self.web_port_var.set(cfg.get("web_port", "5050"))
            self.web_editkey_var.set(cfg.get("web_edit_key", ""))
            self.setting_omdb_key.set(cfg.get("omdb_api_key", OMDB_API_KEY))
            self.railway_base_url_var.set(cfg.get("railway_base_url", "https://movies.toddjarmiolowski.up.railway.app"))
            self.setting_auto_sync.set(cfg.get("auto_sync_railway", False))
        except Exception:
            pass
        # Auto-detect GitHub token from system keyring (preferred over config file).
        # Falls back to any token stored in the JSON config if keyring returns nothing.
        kr_token = keyring_get_gh_token()
        if kr_token:
            self.gh_token_var.set(kr_token)
        else:
            try:
                cfg_fallback = json.loads(self._CONFIG_PATH.read_text())
                self.gh_token_var.set(cfg_fallback.get("gh_token", ""))
            except Exception:
                pass

    def _config_save(self):
        token = self.gh_token_var.get().strip()
        # Persist GitHub token to the system keyring; remove from the JSON config
        # so the plaintext file never contains the secret.
        if not keyring_set_gh_token(token):
            # keyring unavailable — fall back to storing in config (legacy behaviour)
            _token_for_cfg = token
        else:
            _token_for_cfg = ""   # token is safe in keyring; omit from JSON
        cfg = {
            "gh_token":            _token_for_cfg,
            "gh_repo":             self.gh_repo_var.get().strip(),
            "web_port":            self.web_port_var.get().strip(),
            "web_edit_key":        self.web_editkey_var.get().strip(),
            "omdb_api_key":        self.setting_omdb_key.get().strip(),
            "railway_base_url":    self.railway_base_url_var.get().strip(),
            "auto_sync_railway":   self.setting_auto_sync.get(),
        }
        try:
            self._CONFIG_PATH.write_text(json.dumps(cfg, indent=2))
        except Exception as e:
            print(f"[config] save failed: {e}")

    # ── Railway sync ─────────────────────────────────────────────
    def _railway_sync(self):
        token = self.gh_token_var.get().strip()
        repo  = self.gh_repo_var.get().strip()
        if not token:
            messagebox.showerror("Sync", "Please enter your GitHub token.")
            return
        if not repo or "/" not in repo:
            messagebox.showerror("Sync", "Please enter repo as  user/repo-name")
            return
        if not Path(DB_PATH).exists():
            messagebox.showerror("Sync", f"Database not found:\n{DB_PATH}")
            return
        self._sync_btn.config(state="disabled")
        self._sync_status_var.set("Starting sync…")

        def _gh_upsert(path_in_repo, local_bytes, headers):
            """Push one file to GitHub via the Contents API. Returns True on success."""
            api_url  = f"https://api.github.com/repos/{repo}/contents/{path_in_repo}"
            b64      = base64.b64encode(local_bytes).decode()
            get_resp = requests.get(api_url, headers=headers, timeout=15)
            sha      = get_resp.json().get("sha") if get_resp.status_code == 200 else None
            payload  = {"message": f"Film Forge sync: {path_in_repo}", "content": b64}
            if sha:
                payload["sha"] = sha
            put_resp = requests.put(api_url, headers=headers,
                                    data=json.dumps(payload), timeout=60)
            return put_resp.status_code in (200, 201)

        def _do_sync():
            headers = {"Authorization": f"token {token}",
                       "Accept":        "application/vnd.github+json"}
            errors = []
            try:
                # 1. Stamp the DB with the current sync time, then upload
                self.after(0, lambda: self._sync_status_var.set("Uploading database to GitHub…"))
                try:
                    from datetime import datetime as _dt, timezone as _tz
                    sync_ts = _dt.now(_tz.utc).strftime("%Y-%m-%d %H:%M:%S")
                    stamp_db = MovieDB(DB_PATH, None)
                    stamp_db.conn.execute(
                        "CREATE TABLE IF NOT EXISTS ff_meta (key TEXT PRIMARY KEY, value TEXT)"
                    )
                    stamp_db.conn.execute(
                        "INSERT OR REPLACE INTO ff_meta (key, value) VALUES ('last_synced', ?)",
                        (sync_ts,)
                    )
                    if OMDB_API_KEY:
                        stamp_db.conn.execute(
                            "INSERT OR REPLACE INTO ff_meta (key, value) VALUES ('omdb_api_key', ?)",
                            (OMDB_API_KEY,)
                        )
                    stamp_db.conn.commit()
                    stamp_db.close()
                except Exception as e:
                    print(f"[sync] could not stamp timestamp: {e}")

                try:
                    db_bytes = Path(DB_PATH).read_bytes()
                    ok = _gh_upsert("film_forge.db", db_bytes, headers)
                    print(f"[sync] DB upload {'OK' if ok else 'FAILED'}")
                    if not ok:
                        errors.append("database upload failed")
                except Exception as e:
                    print(f"[sync] DB upload exception: {e}")
                    errors.append(f"database: {e}")

                # 1b. Upload film_forge_web.py
                self.after(0, lambda: self._sync_status_var.set("Uploading web server code…"))
                try:
                    web_script = Path(__file__).parent / "film_forge_web.py"
                    if web_script.exists():
                        ok = _gh_upsert("film_forge_web.py", web_script.read_bytes(), headers)
                        print(f"[sync] web script upload {'OK' if ok else 'FAILED'}")
                        if not ok:
                            errors.append("film_forge_web.py upload failed")
                    else:
                        print(f"[sync] film_forge_web.py not found at {web_script} — skipping")
                except Exception as e:
                    print(f"[sync] web script exception: {e}")
                    errors.append(f"film_forge_web.py: {e}")

                # 1c. Ensure Procfile uses gunicorn
                self.after(0, lambda: self._sync_status_var.set("Uploading Procfile…"))
                try:
                    procfile = b"web: gunicorn film_forge_web:app --bind 0.0.0.0:$PORT\n"
                    ok = _gh_upsert("Procfile", procfile, headers)
                    print(f"[sync] Procfile upload {'OK' if ok else 'FAILED'}")
                    if not ok:
                        errors.append("Procfile upload failed")
                except Exception as e:
                    print(f"[sync] Procfile exception: {e}")
                    errors.append(f"Procfile: {e}")

                # 1d. Ensure requirements.txt has all needed packages
                self.after(0, lambda: self._sync_status_var.set("Uploading requirements.txt…"))
                try:
                    reqs = b"flask\nflask-cors\nrequests\ngunicorn\n"
                    ok = _gh_upsert("requirements.txt", reqs, headers)
                    print(f"[sync] requirements.txt upload {'OK' if ok else 'FAILED'}")
                    if not ok:
                        errors.append("requirements.txt upload failed")
                except Exception as e:
                    print(f"[sync] requirements.txt exception: {e}")
                    errors.append(f"requirements.txt: {e}")

                # 2. Report result
                def _finish():
                    self._sync_btn.config(state="normal")
                    self._config_save()
                    if errors:
                        self._sync_status_var.set(f"✘  Sync failed: {errors[0]}")
                    else:
                        self._sync_status_var.set(
                            "✔  Database synced! Railway will redeploy in ~30 seconds.")
                self.after(0, _finish)

            except Exception as _outer_exc:
                print(f"[sync] unexpected crash: {_outer_exc}")
                def _fail(e=str(_outer_exc)):
                    self._sync_btn.config(state="normal")
                    self._sync_status_var.set(f"✘  Sync error: {e}")
                self.after(0, _fail)

        threading.Thread(target=_do_sync, daemon=True).start()

    # ── Pull ratings/watched from Railway ────────────────────────
    def _railway_pull(self):
        """Fetch watched + personal_rating from the live Railway site and merge
        into the local DB.  Most-recent timestamp wins for each field."""
        base_url = self.railway_base_url_var.get().strip().rstrip("/")
        if not base_url:
            messagebox.showerror("Pull", "Please enter your Railway base URL in Settings.")
            return
        if not Path(DB_PATH).exists():
            messagebox.showerror("Pull", f"Local database not found:\n{DB_PATH}")
            return

        self._pull_btn.config(state="disabled")
        self._sync_status_var.set("Pulling ratings from web…")

        def _do_pull():
            try:
                import urllib3
                urllib3.disable_warnings(urllib3.exceptions.InsecureRequestWarning)
                session = requests.Session()
                session.headers.update({"Accept": "application/json"})
                session.verify = False

                # ── 1. Paginate through /api/movies ──────────────
                all_movies = []
                page = 1
                while True:
                    url = f"{base_url}/api/movies?per_page=100&page={page}&sort=title"
                    self.after(0, lambda p=page: self._sync_status_var.set(
                        f"Fetching page {p} from web…"))
                    resp = session.get(url, timeout=20)
                    resp.raise_for_status()
                    data = resp.json()
                    if not data.get("ok"):
                        raise ValueError(data.get("error", "API returned ok=false"))
                    movies = data.get("movies", [])
                    all_movies.extend(movies)
                    if page >= data.get("pages", 1):
                        break
                    page += 1

                # ── 2. Merge into local DB ────────────────────────
                self.after(0, lambda: self._sync_status_var.set(
                    f"Merging {len(all_movies)} records into local database…"))

                db = MovieDB(DB_PATH, None)
                updated_watched = 0
                updated_rating  = 0
                skipped         = 0

                for m in all_movies:
                    imdb_id = (m.get("imdb_id") or "").strip()
                    if not imdb_id:
                        skipped += 1
                        continue

                    web_watched  = bool(m.get("watched"))
                    web_rating   = m.get("personal_rating")   # float or None
                    web_watched_at = m.get("last_watched_at") or ""
                    web_rated_at   = m.get("last_rated_at")   or ""

                    # Fetch local record's timestamps for comparison
                    row = db.conn.execute(
                        """SELECT COALESCE(um.watched, 0)      AS watched,
                                  um.personal_rating           AS personal_rating,
                                  um.last_watched_at           AS last_watched_at,
                                  um.last_rated_at             AS last_rated_at
                           FROM   movies m
                           LEFT JOIN user_movie um ON um.movie_id = m.movie_id
                           WHERE  m.imdb_id = ?""",
                        (imdb_id,)
                    ).fetchone()

                    if row is None:
                        skipped += 1   # movie not in local DB yet
                        continue

                    local_watched_at = (row["last_watched_at"] or "")
                    local_rated_at   = (row["last_rated_at"]   or "")

                    # watched: web wins when its timestamp is newer (or local has none)
                    if web_watched_at and web_watched_at > local_watched_at:
                        db.set_watched(imdb_id, 1 if web_watched else 0)
                        updated_watched += 1

                    # rating: web wins when its timestamp is newer (or local has none)
                    if web_rated_at and web_rated_at > local_rated_at:
                        db.set_rating(imdb_id, web_rating)
                        updated_rating += 1

                db.close()

                def _finish_ok():
                    self._pull_btn.config(state="normal")
                    msg = (f"✔  Pull complete — "
                           f"{updated_watched} watched, {updated_rating} ratings updated"
                           + (f", {skipped} skipped (not in local DB)" if skipped else ""))
                    self._sync_status_var.set(msg)
                    # Refresh the movie list so changes appear immediately
                    self._startup_load_from_db()

                self.after(0, _finish_ok)

            except Exception as exc:
                def _finish_err(e=exc):
                    self._pull_btn.config(state="normal")
                    self._sync_status_var.set(f"✘  Pull failed: {e}")
                    messagebox.showerror("Pull failed", str(e))
                self.after(0, _finish_err)

        threading.Thread(target=_do_pull, daemon=True).start()

    # ── Web server ───────────────────────────────────────────────
    def _web_start(self):
        if self._web_server_running:
            return
        try:
            port = int(self.web_port_var.get().strip())
        except ValueError:
            messagebox.showerror("Web Server", "Port must be a number.")
            return

        edit_key = self.web_editkey_var.get().strip()
        mode     = self.web_mode_var.get()

        if not _FLASK_AVAILABLE:
            messagebox.showerror("Web Server",
                "Flask is not installed.\nRun: pip install flask flask-cors")
            return

        global WEB_DB_PATH, WEB_EDIT_KEY
        WEB_DB_PATH  = DB_PATH
        WEB_EDIT_KEY = edit_key

        flask_host = "127.0.0.1"
        try:
            from werkzeug.serving import make_server
            self._web_wsgi = make_server(flask_host, port, _flask_app)
        except OSError as e:
            messagebox.showerror("Web Server", f"Could not bind to {flask_host}:{port}\n\n{e}")
            return

        self._web_server_running = True
        self._web_status_var.set("Starting…")

        def _serve():
            try:
                self._web_wsgi.serve_forever()
            except Exception:
                pass
            self._web_server_running = False
            self.after(0, self._web_update_buttons)

        self._web_server_thread = threading.Thread(target=_serve, daemon=True)
        self._web_server_thread.start()

        if mode == "funnel":
            self._web_start_funnel(port)
        else:
            try:
                self._web_wsgi.socket.close()
            except Exception:
                pass
            try:
                from werkzeug.serving import make_server
                self._web_wsgi = make_server("0.0.0.0", port, _flask_app)
            except Exception:
                pass
            try:
                lan_ip = socket.gethostbyname(socket.gethostname())
            except Exception:
                lan_ip = "your-pc-ip"
            self._web_url = f"http://{lan_ip}:{port}"
            self._web_status_var.set(f"✔  LAN:  {self._web_url}  — share with people on your WiFi")
            self._web_update_buttons()

    def _web_start_funnel(self, port: int):
        ts = shutil.which("tailscale")
        if not ts:
            ts = r"C:\Program Files\Tailscale\tailscale.exe"
            if not Path(ts).exists():
                self._web_status_var.set("✘  Tailscale not found. Install from tailscale.com then retry.")
                self._web_stop_flask_only()
                return
        self._web_status_var.set("Starting Tailscale Funnel… (may take a few seconds)")

        def _run_funnel():
            try:
                proc   = subprocess.run([ts, "funnel", "--bg", str(port)],
                                        capture_output=True, text=True, timeout=30)
                output = (proc.stdout or "") + (proc.stderr or "")
                m = re.search(r"https://\S+\.ts\.net\S*", output) or re.search(r"https://\S+", output)
                if m:
                    url = m.group(0).rstrip("/|")
                    self._web_url = url
                    def _ok():
                        self._web_status_var.set(f"✔  Public (Tailscale):  {url}\n   Share this link — anyone on the internet can use it.")
                        self._web_update_buttons()
                    self.after(0, _ok)
                elif proc.returncode != 0:
                    err = (output.strip() or "Unknown error")
                    def _fail():
                        self._web_status_var.set(f"✘  Tailscale Funnel failed:\n   {err}")
                        self._web_stop_flask_only()
                        self._web_update_buttons()
                    self.after(0, _fail)
                else:
                    status = subprocess.run([ts, "funnel", "status"],
                                            capture_output=True, text=True, timeout=10)
                    sm  = re.search(r"https://\S+", status.stdout or "")
                    url = sm.group(0).rstrip("/|") if sm else f"http://localhost:{port}"
                    self._web_url = url
                    def _ok2():
                        self._web_status_var.set(f"✔  Public (Tailscale):  {url}")
                        self._web_update_buttons()
                    self.after(0, _ok2)
            except subprocess.TimeoutExpired:
                def _timeout():
                    self._web_status_var.set("✘  Tailscale timed out. Is Tailscale running?")
                    self._web_stop_flask_only()
                    self._web_update_buttons()
                self.after(0, _timeout)
            except Exception as e:
                def _err(msg=str(e)):
                    self._web_status_var.set(f"✘  Funnel error: {msg}")
                    self._web_stop_flask_only()
                    self._web_update_buttons()
                self.after(0, _err)

        threading.Thread(target=_run_funnel, daemon=True).start()

    def _web_stop_flask_only(self):
        try:
            self._web_wsgi.shutdown()
        except Exception:
            pass
        self._web_server_running = False

    def _web_stop(self):
        self._web_stop_flask_only()
        if self.web_mode_var.get() == "funnel":
            ts = shutil.which("tailscale") or r"C:\Program Files\Tailscale\tailscale.exe"
            try:
                port = int(self.web_port_var.get().strip())
                subprocess.run([ts, "funnel", "--bg", str(port), "off"],
                               capture_output=True, timeout=10)
            except Exception:
                pass
        self._web_url = ""
        self._web_status_var.set("Server stopped.")
        self._web_update_buttons()

    def _web_open(self):
        if self._web_url:
            webbrowser.open(self._web_url)

    def _web_copy_url(self):
        if self._web_url:
            self.clipboard_clear()
            self.clipboard_append(self._web_url)
            self._web_status_var.set(f"✔  Copied:  {self._web_url}")

    def _web_update_buttons(self):
        running = self._web_server_running
        self._web_btn_start.config(state="disabled" if running else "normal")
        self._web_btn_stop.config (state="normal"   if running else "disabled")
        has_url = bool(self._web_url)
        self._web_btn_open.config(state="normal" if has_url else "disabled")
        self._web_btn_copy.config(state="normal" if has_url else "disabled")

    # ── Status bar ───────────────────────────────────────────────
    def _build_statusbar(self, parent):
        parent.columnconfigure(0, weight=1)
        ttk.Label(parent, textvariable=self.status_var).grid(row=0, column=0, sticky="w")
        self.counters_label = ttk.Label(parent, text="")
        self.counters_label.grid(row=0, column=1, sticky="e", padx=(10, 0))
        row = ttk.Frame(parent)
        row.grid(row=1, column=0, columnspan=2, sticky="ew", pady=(6, 0))
        row.columnconfigure(0, weight=1)
        self.progress   = ttk.Progressbar(row, mode="determinate")
        self.progress.grid(row=0, column=0, sticky="ew")
        self.btn_cancel = ttk.Button(row, text="Cancel", command=self.on_cancel)
        self.btn_cancel.grid(row=0, column=1, padx=(10, 0))
        self._refresh_counters()

    # ── UI helpers ───────────────────────────────────────────────
    def _refresh_counters(self):
        self.counters_label.config(text=(
            f"Movies: {self.movies_var.get()}  |  "
            f"Processed: {self.processed_var.get()}  |  "
            f"Skipped: {self.skipped_var.get()}  |  "
            f"ETA: {self.eta_var.get()}"
        ))

    def _set_idle_state(self):
        has_folder = len(self.folders_tree.get_children()) > 0
        has_movies = len(self.movies_tree.get_children()) > 0
        self.btn_remove.config(state="normal" if has_folder else "disabled")
        self.btn_scan.config(  state="normal" if has_folder else "disabled")
        self.btn_fetch.config( state="normal" if has_movies else "disabled")
        self.btn_export.config(state="normal" if has_movies else "disabled")
        self.btn_cancel.config(state="disabled")
        self._refresh_counters()

    def _set_busy_state(self, status: str):
        self.status_var.set(status)
        for b in (self.btn_add, self.btn_remove, self.btn_scan, self.btn_fetch, self.btn_export):
            b.config(state="disabled")
        self.btn_cancel.config(state="normal")

    def _clear_movies(self):
        for item in self.movies_tree.get_children():
            self.movies_tree.delete(item)
        self.details_by_item.clear()
        self.movies_var.set(0)
        self.processed_var.set("0/0")
        self.skipped_var.set(0)
        self.eta_var.set("—")
        self.progress.stop()
        self.progress.config(value=0, maximum=0, mode="determinate")
        self._refresh_counters()

    # ── Button handlers ──────────────────────────────────────────
    def on_add_folders(self):
        folder = filedialog.askdirectory(title="Select folder to scan")
        if not folder:
            return
        self.folders_tree.insert("", "end", values=(folder,))
        self.status_var.set("Folder added")
        self._set_idle_state()

    def on_remove_folders(self):
        for item in self.folders_tree.selection():
            self.folders_tree.delete(item)
        self.status_var.set("Folder(s) removed")
        self._set_idle_state()

    def on_start_scan(self):
        folders = [self.folders_tree.item(i, "values")[0] for i in self.folders_tree.get_children()]
        if not folders:
            messagebox.showinfo("Scan", "Please add at least one folder first.")
            return
        self._clear_movies()
        self._cancel_event.clear()
        self._set_busy_state("Scanning…")

        def ui_update(total_scanned, video_found):
            if self._cancel_event.is_set():
                return
            self.after(0, lambda: self.status_var.set(
                f"Scanning… {total_scanned:,} files checked | {video_found:,} videos found"))

        def worker():
            try:
                video_files  = scan_for_video_files(folders, update_callback=ui_update)
                movie_titles = []
                for fp in video_files:
                    if self._cancel_event.is_set():
                        break
                    title, year, edition, imdb_id = extract_title_year_imdb(fp)
                    movie_titles.append((title, year, edition, imdb_id, fp))
                self.movie_titles = movie_titles

                try:
                    db = MovieDB(DB_PATH, None)
                    for (t, y, _ed, iid, fp) in movie_titles:
                        if self._cancel_event.is_set():
                            break
                        try:
                            mid = db.upsert_movie({"imdbID": iid or "", "Title": t or "", "Year": y or ""})
                            if fp:
                                db.upsert_file(mid, fp, do_hash=False)
                        except Exception:
                            pass
                    db.close()
                except Exception as db_err:
                    print(f"[scan] DB persist error: {db_err}")

                def finish():
                    cancelled = self._cancel_event.is_set()
                    for (title, year, _ed, _id, _fp) in self.movie_titles:
                        self.movies_tree.insert("", "end", values=(title or "", year or "", "", "", "", ""))
                    self.movies_var.set(len(self.movie_titles))
                    self.processed_var.set(f"0/{len(self.movie_titles)}")
                    suffix = " (cancelled)" if cancelled else ""
                    self.status_var.set(f"Scan complete{suffix} — {len(self.movie_titles):,} movie files found")
                    self._db_loaded_once = False
                    self._set_idle_state()
                self.after(0, finish)
            except Exception as e:
                self.after(0, lambda: messagebox.showerror("Scan Error", str(e)))
                self.after(0, self._set_idle_state)

        threading.Thread(target=worker, daemon=True).start()

    def on_fetch_details(self):
        if not getattr(self, "movie_titles", None):
            messagebox.showinfo("Fetch Details", "Run a scan first.")
            return
        total = len(self.movie_titles)

        # ── Centered confirmation: file count + time estimate ─────
        est_secs  = total * 2          # rough ~2 seconds per title
        if est_secs < 60:
            est_str = f"{est_secs} seconds"
        elif est_secs < 3600:
            est_str = f"{est_secs // 60}m {est_secs % 60}s"
        else:
            hrs = est_secs // 3600
            mins = (est_secs % 3600) // 60
            est_str = f"{hrs}h {mins}m"
        msg = (f"{total:,} file{'s' if total != 1 else ''} to process.\n\n"
               f"Estimated time: ~{est_str}.\n\n"
               f"This might take some time — continue?")
        if not messagebox.askyesno("Fetch Details", msg):
            return

        self._cancel_event.clear()
        self._set_busy_state("Fetching details…")
        self.progress.config(mode="determinate", maximum=total, value=0)

        def worker():
            skipped      = 0
            skipped_log  = []   # list of (title, year, file_path, reason)
            start_time   = time.time()
            try:
                db = MovieDB(DB_PATH, None)
            except Exception as e:
                self.after(0, lambda: messagebox.showerror("DB", f"Cannot open database:\n{e}"))
                self.after(0, self._set_idle_state)
                return

            for i, (title, year, edition, imdb_id, file_path) in enumerate(self.movie_titles, start=1):
                if self._cancel_event.is_set():
                    break
                runtime = rated = genre = actors = plot = poster_url = ""
                new_title  = title or ""
                new_year   = year  or ""
                fetched_id = imdb_id or ""
                skip_reason = None
                try:
                    if imdb_id:
                        data = fetch_data_by_imdb_id(imdb_id, session=OMDB_SESSION)
                    else:
                        data = fetch_data_by_title_year(title, year, session=OMDB_SESSION)
                    if data and any(data):
                        _imdb, corrected_title, runtime, _genre, rated, _actors, _plot, _poster_url = data
                        fetched_id    = _imdb  or imdb_id or ""
                        genre         = _genre  or ""
                        actors        = _actors or ""
                        plot          = _plot   or ""
                        remote_poster = _poster_url or ""
                        if corrected_title:
                            new_title = corrected_title
                        if remote_poster and fetched_id:
                            poster_url = download_poster(fetched_id, remote_poster)
                        else:
                            poster_url = remote_poster
                    else:
                        skip_reason = "No OMDb match found"
                        skipped += 1
                        skipped_log.append((title or "?", year or "?", file_path or "", skip_reason))
                except Exception as exc:
                    skip_reason = f"Error: {exc}"
                    skipped += 1
                    skipped_log.append((title or "?", year or "?", file_path or "", skip_reason))

                try:
                    movie_id_db = db.upsert_movie({
                        "imdbID": fetched_id, "Title": new_title, "Year": new_year,
                        "Runtime": runtime, "Genre": genre, "Rated": rated,
                        "Actors": actors, "Plot": plot, "Poster": poster_url,
                    })
                    if file_path:
                        db.upsert_file(movie_id_db, file_path, do_hash=HASH_DURING_PROCESS)
                except Exception as db_err:
                    print(f"[fetch] DB write failed for {new_title!r}: {db_err}")

                elapsed = time.time() - start_time
                avg     = elapsed / i
                eta_s   = int(avg * (total - i))
                eta_str = f"{eta_s // 60}m {eta_s % 60}s" if eta_s >= 60 else f"{eta_s}s"

                def apply_ui(idx=i-1, t=new_title, y=new_year, rt=runtime, mpaa=rated,
                             g=genre, ac=actors, pl=plot, pu=poster_url,
                             s=skipped, cur=i, tot=total, eta=eta_str):
                    self.progress.config(value=cur)
                    self.processed_var.set(f"{cur}/{tot}")
                    self.skipped_var.set(s)
                    self.eta_var.set(eta)
                    self._refresh_counters()
                    items = self.movies_tree.get_children()
                    if 0 <= idx < len(items):
                        item_id = items[idx]
                        self.details_by_item[item_id] = {
                            "genre": g, "actors": ac, "plot": pl, "poster_url": pu}
                        old     = self.movies_tree.item(item_id, "values")
                        watched = old[4] if len(old) > 4 else ""
                        rating  = old[5] if len(old) > 5 else ""
                        self.movies_tree.item(item_id, values=(t, y, rt, mpaa, watched, rating))
                self.after(0, apply_ui)

            db.close()

            def finish():
                cancelled = self._cancel_event.is_set()
                self.status_var.set(f"Fetch complete{' (cancelled)' if cancelled else ''}")
                self._db_loaded_once = False
                self._set_idle_state()
                if skipped_log:
                    self._show_skipped_report(skipped_log)
                if not cancelled and self.setting_auto_sync.get():
                    self._sync_status_var.set("Auto-sync: starting…")
                    self._railway_sync()
            self.after(0, finish)

        threading.Thread(target=worker, daemon=True).start()

    def _show_skipped_report(self, skipped_log):
        """Show a scrollable window listing every skipped file and the reason."""
        win = tk.Toplevel(self)
        win.title(f"Skipped Files Report  ({len(skipped_log)} skipped)")
        win.geometry("820x480")
        center_window(win, self)
        win.resizable(True, True)

        # Header
        hdr = ttk.Frame(win, padding=(10, 8, 10, 4))
        hdr.pack(fill="x")
        ttk.Label(hdr,
                  text=f"{len(skipped_log)} file(s) were skipped during fetch.",
                  font=("", 10, "bold")).pack(side="left")
        ttk.Button(hdr, text="Copy to Clipboard",
                   command=lambda: self._copy_skipped_to_clipboard(skipped_log, win)
                   ).pack(side="right")

        # Treeview with columns: Title, Year, Reason, File Path
        frame = ttk.Frame(win, padding=(10, 0, 10, 10))
        frame.pack(fill="both", expand=True)
        frame.columnconfigure(0, weight=1)
        frame.rowconfigure(0, weight=1)

        cols = ("title", "year", "reason", "filepath")
        tree = ttk.Treeview(frame, columns=cols, show="headings", selectmode="browse")
        tree.heading("title",    text="Title")
        tree.heading("year",     text="Year")
        tree.heading("reason",   text="Reason")
        tree.heading("filepath", text="File Path")
        tree.column("title",    width=200, stretch=True)
        tree.column("year",     width=55,  stretch=False, anchor="center")
        tree.column("reason",   width=200, stretch=True)
        tree.column("filepath", width=300, stretch=True)

        vsb = ttk.Scrollbar(frame, orient="vertical",   command=tree.yview)
        hsb = ttk.Scrollbar(frame, orient="horizontal", command=tree.xview)
        tree.configure(yscrollcommand=vsb.set, xscrollcommand=hsb.set)

        tree.grid(row=0, column=0, sticky="nsew")
        vsb.grid( row=0, column=1, sticky="ns")
        hsb.grid( row=1, column=0, sticky="ew")

        for title, year, filepath, reason in skipped_log:
            fname = Path(filepath).name if filepath else ""
            tree.insert("", "end", values=(title, year, reason, fname),
                        tags=("row",))
            # Store full path as a tooltip-style tag for copy
            tree.item(tree.get_children()[-1], tags=(filepath,))

        # Show full file path in a label when a row is selected
        path_var = tk.StringVar(value="")
        ttk.Label(win, textvariable=path_var, wraplength=780,
                  style="Small.TLabel").pack(padx=10, pady=(0, 6), anchor="w")

        def on_select(_evt):
            sel = tree.selection()
            if sel:
                path_var.set(tree.item(sel[0], "tags")[0] or "")
        tree.bind("<<TreeviewSelect>>", on_select)

        ttk.Button(win, text="Close", command=win.destroy).pack(pady=(0, 8))

    def _copy_skipped_to_clipboard(self, skipped_log, win):
        lines = ["Title\tYear\tReason\tFile Path"]
        for title, year, filepath, reason in skipped_log:
            lines.append(f"{title}\t{year}\t{reason}\t{filepath}")
        win.clipboard_clear()
        win.clipboard_append("\n".join(lines))

    def on_cancel(self):
        self._cancel_event.set()
        self.status_var.set("Cancelling… (finishing current item)")
        self.btn_cancel.config(state="disabled")

    def on_exit(self):
        self._config_save()
        # Shut down web server safely without touching widgets (avoids hang)
        try:
            self._web_wsgi.shutdown()
        except Exception:
            pass
        self._web_server_running = False
        self.destroy()
        import sys as _sys
        _sys.exit(0)

    def on_movie_selected(self, _evt=None):
        sel = self.movies_tree.selection()
        if not sel:
            return
        item_id = sel[0]
        values  = self.movies_tree.item(item_id, "values")
        title   = values[0] if len(values) > 0 else ""
        year    = values[1] if len(values) > 1 else ""
        runtime = values[2] if len(values) > 2 else ""
        mpaa    = values[3] if len(values) > 3 else ""
        self.details_title_var.set(title)
        self.details_meta_var.set(f"{year} | {runtime} | {mpaa}")
        d = self.details_by_item.get(item_id, {})
        self.details_genre_var.set(d.get("genre",  ""))
        self.details_actors_var.set(d.get("actors", ""))
        self.details_plot_text.delete("1.0", "end")
        self.details_plot_text.insert("1.0", d.get("plot", ""))
        poster_url = d.get("poster_url", "")
        items   = self.movies_tree.get_children()
        imdb_id = ""
        try:
            idx = list(items).index(item_id)
            if 0 <= idx < len(self.movie_titles):
                imdb_id = self.movie_titles[idx][3] or ""
        except (ValueError, IndexError):
            pass
        if poster_url and poster_url.lower() not in ("", "n/a"):
            self._poster_load(imdb_id, poster_url)
        elif imdb_id:
            self._poster_load_for_imdb(imdb_id, title, year)
        else:
            self._poster_load_for_imdb("", title, year)


