def _run_web_server_cli():
    """Run the Flask web server from the command line (replaces film_forge_web.py __main__)."""
    global WEB_DB_PATH, WEB_EDIT_KEY
    ap = argparse.ArgumentParser(description="MDC Web Server")
    ap.add_argument("--db",       default=DB_PATH)
    ap.add_argument("--schema",   default="")
    ap.add_argument("--host",     default="127.0.0.1")
    ap.add_argument("--port",     default=5050, type=int)
    ap.add_argument("--edit-key", default="")
    args         = ap.parse_args()
    WEB_DB_PATH  = args.db
    WEB_EDIT_KEY = (args.edit_key or "").strip()

    if not _FLASK_AVAILABLE:
        print("Flask is not installed. Run: pip install flask flask-cors")
        sys.exit(1)

    print(f"Starting MDC Web Server on {args.host}:{args.port}")
    print(f"Database: {WEB_DB_PATH}")
    _flask_app.run(host=args.host, port=args.port, debug=False)


if __name__ == "__main__":
    # If called as: python film_forge.py --web  → start web server only
    if "--web" in sys.argv:
        sys.argv.remove("--web")
        _run_web_server_cli()
    else:
        root = tk.Tk()
        root.withdraw()                      # hide root; splash is its own Toplevel
        splash = SplashScreen(root)
        _load_embedded_icon(root)
        root.update()                        # pump event loop so splash paints immediately

        def _launch():
            splash.close()
            root.destroy()
            app = FilmForgeUI()
            # Maximise the main window on every platform
            try:
                app.state("zoomed")          # Windows & macOS
            except Exception:
                try:
                    app.attributes("-zoomed", True)   # Linux / X11
                except Exception:
                    pass
            app.mainloop()

        root.after(SplashScreen.DURATION_MS, _launch)
        root.mainloop()
